function lineObjects(){return planObjects.filter(o=>o.x2!==undefined)}
function productionGeometryChecks(){const issues=[];const complex=points.length>6||selfIntersects();if(complex&&!diagonals.length)issues.push({state:'warn',title:'РўСЂРёР°РЅРіСѓР»СЏС†РёСЏ СЃР»РѕР¶РЅРѕРіРѕ РєРѕРЅС‚СѓСЂР°',detail:'Р”Р»СЏ РјРЅРѕРіРѕСѓРіРѕР»СЊРЅРёРєР° РґРѕР±Р°РІСЊС‚Рµ РјРёРЅРёРјСѓРј РѕРґРЅСѓ РєРѕРЅС‚СЂРѕР»СЊРЅСѓСЋ РґРёР°РіРѕРЅР°Р»СЊ.'});lineObjects().forEach((o,i)=>{const len=dist(o,{x:o.x2,y:o.y2});if(len<0.2)issues.push({state:'error',title:`Р›РёРЅРµР№РЅС‹Р№ РѕР±СЉРµРєС‚ ${i+1}`,detail:'Р”Р»РёРЅР° Р»РёРЅРёРё РјРµРЅСЊС€Рµ 0,2 Рј.'});if(!o.geometryAligned)issues.push({state:'warn',title:`Р›РёРЅРµР№РЅС‹Р№ РѕР±СЉРµРєС‚ ${i+1}`,detail:'Р›РёРЅРёСЏ РµС‰С‘ РЅРµ РїСЂРёРІСЏР·Р°РЅР° Рє РіРµРѕРјРµС‚СЂРёРё СЃС‚РµРЅС‹.'})});return issues}
