function roomDiagnostics(){const result=[];if(selfIntersects())result.push({state:'error',title:'РЎР°РјРѕРїРµСЂРµСЃРµС‡РµРЅРёРµ РєРѕРЅС‚СѓСЂР°',detail:'РџСЂРѕРІРµСЂСЊС‚Рµ РїРѕСЂСЏРґРѕРє РІРµСЂС€РёРЅ Рё РїРѕРІС‚РѕСЂРёС‚Рµ Р·Р°РјРµСЂ.'});points.forEach((p,i)=>{const angle=interiorAngle(i);if(angle<25||angle>335)result.push({state:'warn',title:`РЈРіРѕР» ${vertexName(i)}`,detail:`РћСЃС‚СЂС‹Р№ СѓРіРѕР» ${fmt(angle,1)}В°. РќСѓР¶РЅР° РєРѕРЅС‚СЂРѕР»СЊРЅР°СЏ РїСЂРѕРІРµСЂРєР° РЅР° РѕР±СЉРµРєС‚Рµ.`});});for(let i=0;i<points.length;i++){const len=dist(points[i],points[(i+1)%points.length]);if(len<.15)result.push({state:'error',title:`РЎС‚РѕСЂРѕРЅР° ${vertexName(i)}вЂ“${vertexName((i+1)%points.length)}`,detail:'РЎС‚РѕСЂРѕРЅР° РєРѕСЂРѕС‡Рµ 0,15 Рј Рё С‚СЂРµР±СѓРµС‚ РёСЃРїСЂР°РІР»РµРЅРёСЏ.'})}return result}
var diagnosticsBase=productionGeometryChecks;
