var alignBase=alignLineToRoom;
alignLineToRoom=function(a,b){const aligned=alignBase(a,b);let dx=aligned.x2-aligned.x,dy=aligned.y2-aligned.y,len=Math.hypot(dx,dy)||1;const ux=dx/len,uy=dy/len;for(let i=0;i<points.length;i++){const s=points[i],e=points[(i+1)%points.length],ex=e.x-s.x,ey=e.y-s.y,el=Math.hypot(ex,ey)||1,tx=ex/el,ty=ey/el;if(Math.abs(tx*ux+ty*uy)>.94){const cx=(aligned.x+aligned.x2)/2,cy=(aligned.y+aligned.y2)/2,proj=(cx-s.x)*tx+(cy-s.y)*ty,half=Math.min(len/2,el/2),clamped=Math.max(half,Math.min(el-half,proj));const center={x:s.x+tx*clamped,y:s.y+ty*clamped};return{x:center.x-ux*half,y:center.y-uy*half,x2:center.x+ux*half,y2:center.y+uy*half}}}return aligned};
